from myUtils.Utils import printResult
from typing import List

"""
You are given an m x n coins. A robot starts at the top-left corner of the coins (0, 0) and wants to reach the bottom-right corner (m - 1, n - 1). The robot can move either right or down at any point in time.

The coins contains a value coins[i][j] in each cell:

If coins[i][j] >= 0, the robot gains that many coins.
If coins[i][j] < 0, the robot encounters a robber, and the robber steals the absolute value of coins[i][j] coins.
The robot has a special ability to neutralize robbers in at most 2 cells on its path, preventing them from stealing coins in those cells.

Note: The robot's total coins can be negative.

Return the maximum profit the robot can gain on the route.
"""

class Solution:
    def maximumAmount(self, coins: List[List[int]]) -> int:
        m, n = len(coins), len(coins[0])
        
        # dp[r][c][k] is the maximum profit reaching cell (r, c) with k neutralizations REMAINING
        # Initialize with a very small number
        INF = float('inf')
        dp = [[[-INF] * 3 for _ in range(n)] for _ in range(m)]

        # Base case: start at (0, 0)
        # Option 1: Don't neutralize (0, 0)
        dp[0][0][2] = coins[0][0]
        # Option 2: Neutralize (0, 0) if it's a robber
        if coins[0][0] < 0:
            dp[0][0][1] = 0

        for r in range(m):
            for c in range(n):
                for k in range(3):
                    if dp[r][c][k] == -INF:
                        continue
                    
                    # Try moving to the next cell (Right or Down)
                    for dr, dc in [(0, 1), (1, 0)]:
                        nr, nc = r + dr, c + dc
                        
                        if nr < m and nc < n:
                            val = coins[nr][nc]
                            
                            # Choice A: Don't neutralize the next cell
                            dp[nr][nc][k] = max(dp[nr][nc][k], dp[r][c][k] + val)
                            
                            # Choice B: Neutralize the next cell (if it's a robber and we have uses left)
                            if val < 0 and k > 0:
                                dp[nr][nc][k-1] = max(dp[nr][nc][k-1], dp[r][c][k])

        return max(dp[m-1][n-1])

obj = Solution()

coins = [[0,1,-1],[1,-2,3],[2,-3,4]]
expected = 8
result = obj.maximumAmount(coins)
printResult(result, expected)

coins = [[10,10,10],[10,10,10]]
expected = 40
result = obj.maximumAmount(coins)
printResult(result, expected)

